export const SUBJECT_LIST = Object.keys(SYLLABUS).sort();

export function getSubjectMeta(s) {
  return SYLLABUS[s?.toLowerCase()] ?? {
    label:(s||'').replace(/_/g,' '), icon:'📚', color:'#6B7280',
    bg:'#1A1A1A', desc:'', hasImages:false, books:[], datasets:[],
  };
}

export function getStaticBooks(s)    { return SYLLABUS[s?.toLowerCase()]?.books    ?? []; }
export function getStaticDatasets(s) { return SYLLABUS[s?.toLowerCase()]?.datasets ?? []; }
export function getStaticChapters(s, bookName) {
  const book = getStaticBooks(s).find(b => b.name === bookName);
  return book?.chapters ?? [];
}